fun solve(nums: Array<Long>, k: Long): Long {
    return if (nums.size == 1) 0L else {
        val sorted = nums.sorted()
        var minRemove = nums.size.toLong()
        for (i in 0 until nums.size) {
            if (sorted.last() <= sorted[i] * k) {
                minRemove = minOf(minRemove, nums.size - i).toLong()
                break
            }
        }
        minRemove
    }
}
